// JWT Token Validation - v2.0.0
// v2.0.0: Fetch JWT_SECRET from app_config

const webhookData = $('Webhook - Save Appointment').first().json;
const jwtSecret = $('Get JWT Secret - Supabase').first().json.value;

if (!jwtSecret) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'JWT secret not configured',
      statusCode: 500,
      timestamp: new Date().toISOString()
    }
  }];
}

const authHeader = webhookData.headers?.authorization
  || webhookData.headers?.Authorization;

if (!authHeader) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Missing authorization header',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

if (!authHeader.startsWith('Bearer ')) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Invalid authorization format',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

const token = authHeader.substring(7);

function simpleHash(input) {
  let hash = 0;
  for (let i = 0; i < input.length; i++) {
    const char = input.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return hash.toString(36);
}

function verifyJWT(tkn, secret) {
  try {
    const parts = tkn.split('.');
    if (parts.length !== 3) {
      return { valid: false, error: 'Invalid token format' };
    }
    const [header, payload, sig] = parts;
    const expected = simpleHash(
      `${header}.${payload}.${secret}`
    );
    if (sig !== expected) {
      return { valid: false, error: 'Invalid token signature' };
    }
    const decoded = JSON.parse(atob(payload));
    const now = Math.floor(Date.now() / 1000);
    if (decoded.exp && decoded.exp < now) {
      return { valid: false, error: 'Token expired' };
    }
    return { valid: true, payload: decoded };
  } catch (e) {
    return { valid: false, error: 'Token verification failed' };
  }
}

const result = verifyJWT(token, jwtSecret);

if (!result.valid) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: result.error || 'Invalid token',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

const p = result.payload;

if (p.type === 'limited') {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Full authentication required',
      statusCode: 403,
      timestamp: new Date().toISOString()
    }
  }];
}

if (p.type === 'refresh') {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Refresh tokens cannot be used',
      statusCode: 403,
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _route: 'authorized',
    authenticated: true,
    user: {
      id: p.user_id || null,
      username: p.sub,
      role: p.role,
      tokenType: p.type
    },
    requestBody: webhookData.body,
    timestamp: new Date().toISOString()
  }
}];
// v2.0.0 - JWT secret from app_config

// Validate Request Data - v3.0.0
// v3.0.0: Type-aware validation, array support

const data = $json.requestBody || $json.body || $json;
const user = $('JWT Validation - Code').first().json.user;

let appointments = [];
if (data.appointments && Array.isArray(data.appointments)) {
  appointments = data.appointments;
} else {
  appointments = [data];
}

if (appointments.length === 0) {
  return [{
    json: {
      _route: 'error',
      success: false,
      message: 'No appointments provided',
      timestamp: new Date().toISOString()
    }
  }];
}

const validTypes = ['round_trip', 'one_way', 'support'];
const validDirs = ['to_clinic', 'to_home'];
const processed = [];

for (let i = 0; i < appointments.length; i++) {
  const apt = appointments[i];
  const errors = [];
  const aptType = apt.appointment_type || 'round_trip';

  if (!validTypes.includes(aptType)) {
    errors.push('Invalid appointment_type: ' + aptType);
  }

  if (!apt.knumber) errors.push('knumber is required');
  if (!apt.appointmentDateTime) {
    errors.push('appointmentDateTime is required');
  }

  if (aptType === 'round_trip' || aptType === 'one_way') {
    if (!apt.location) errors.push('location is required');
    if (!apt.locationAddress) {
      errors.push('locationAddress is required');
    }
  }

  if (aptType === 'one_way') {
    const dir = apt.trip_direction || '';
    if (!validDirs.includes(dir)) {
      errors.push('trip_direction required for one_way');
    }
  }

  if (aptType === 'support') {
    if (!apt.event_name || !apt.event_name.trim()) {
      errors.push('event_name required for support');
    }
  }

  if (apt.appointmentDateTime) {
    try {
      const d = new Date(apt.appointmentDateTime);
      if (isNaN(d.getTime())) {
        errors.push('Invalid appointmentDateTime format');
      }
    } catch (e) {
      errors.push('Invalid appointmentDateTime');
    }
  }

  if (errors.length > 0) {
    console.error(
      `Appt ${i + 1} invalid: ${errors.join(', ')}`
    );
    continue;
  }

  processed.push({
    json: {
      _route: 'valid',
      ...apt,
      appointment_type: aptType,
      trip_direction: apt.trip_direction || null,
      event_name: apt.event_name || null,
      calculate_traffic_transit:
        apt.calculate_traffic_transit === true
          ? 'true' : 'false',
      user: user
    }
  });
}

if (processed.length === 0) {
  return [{
    json: {
      _route: 'error',
      success: false,
      message: 'No valid appointments to process',
      timestamp: new Date().toISOString()
    }
  }];
}

return processed;
// v3.0.0 - Type-aware validation with traffic flag

// Calculate Times - v3.0.0
// Type-aware pickup/dropoff calculations

const items = $input.all();

return items.map(item => {
  const d = item.json;
  const apptDT = new Date(d.appointmentDateTime);
  const transit = parseInt(d.transitTime) || 30;
  const length = parseInt(d.appointmentLength) || 120;
  const aptType = d.appointment_type || 'round_trip';
  const dir = d.trip_direction || 'to_clinic';

  let pickupTime, dropOffTime;

  if (aptType === 'one_way') {
    if (dir === 'to_home') {
      pickupTime = apptDT.toISOString();
      const dropOff = new Date(
        apptDT.getTime() + (transit * 60000)
      );
      dropOffTime = dropOff.toISOString();
    } else {
      const pickup = new Date(
        apptDT.getTime() - (transit * 60000)
      );
      pickupTime = pickup.toISOString();
      dropOffTime = apptDT.toISOString();
    }
  } else if (aptType === 'support') {
    pickupTime = apptDT.toISOString();
    const dropOff = new Date(
      apptDT.getTime() + (length * 60000)
    );
    dropOffTime = dropOff.toISOString();
  } else {
    const pickup = new Date(
      apptDT.getTime() - (transit * 60000)
    );
    pickupTime = pickup.toISOString();
    const total = length + transit;
    const dropOff = new Date(
      apptDT.getTime() + (total * 60000)
    );
    dropOffTime = dropOff.toISOString();
  }

  return {
    json: {
      ...d,
      pickupTime: pickupTime,
      dropOffTime: dropOffTime,
      transitTime: transit,
      appointmentLength: length
    }
  };
});
// v3.0.0 - Type-aware timing calculations

// Combine Notes - v3.0.0
// Merges driver_instructions + scheduling_notes

const items = $input.all();

return items.map(item => {
  const d = item.json;
  const instr = (d.driver_instructions || '').trim();
  const sched = (d.scheduling_notes || '').trim();

  let combined = '';
  if (instr && sched) {
    combined = `${instr}. ${sched}`;
  } else if (instr) {
    combined = instr;
  } else {
    combined = sched;
  }

  return {
    json: {
      ...d,
      scheduling_notes: combined
    }
  };
});
// v3.0.0 - Passes through type fields

// Check Traffic Calc Needed - v1.0.0
// Determines if async traffic calc is needed

const items = $input.all();
const user = items[0]?.json?.user
  || $('Validate Request - Code').first().json.user;

const needsTraffic = [];
const noTraffic = [];

items.forEach(item => {
  const d = item.json;
  const wantTraffic =
    d.calculate_traffic_transit === 'true';
  const isSupport = d.appointment_type === 'support';
  const hasAddresses = d.pickup_address
    && d.locationaddress;

  if (wantTraffic && !isSupport && hasAddresses) {
    needsTraffic.push(d);
  } else {
    noTraffic.push(d);
  }
});

const allResults = items.map(item => ({
  id: item.json.id,
  knumber: item.json.knumber,
  appointmenttime: item.json.appointmenttime,
  pickuptime: item.json.pickuptime,
  location: item.json.locationname,
  appointment_type: item.json.appointment_type
    || 'round_trip',
  trip_direction: item.json.trip_direction || null,
  event_name: item.json.event_name || null
}));

const hasTrafficNeeded = needsTraffic.length > 0;

return [{
  json: {
    _route: hasTrafficNeeded ? 'async' : 'sync',
    allResults: allResults,
    trafficAppointments: needsTraffic,
    successCount: items.length,
    totalCount: items.length,
    user: user
  }
}];
// v1.0.0 - Traffic calc routing

// Create Background Tasks - v1.0.0
// Creates task rows for traffic calc

const data = $input.first().json;
const appts = data.trafficAppointments;
const user = data.user;

const tasks = appts.map(apt => ({
  json: {
    entity_type: 'appointment',
    entity_id: String(apt.id),
    entity_label: apt.knumber + ' - '
      + (apt.locationname || apt.event_name || 'Appt'),
    task_type: 'calculate_traffic_transit',
    status: 'pending',
    created_by: user?.id || null,
    appointmentData: apt
  }
}));

return tasks;
// v1.0.0 - Create traffic calc tasks

// Format Async Response - v1.0.0
// Returns appointments + background task IDs

const taskResults = $input.all();
const routeData = $('Check Traffic Calc Needed - Code')
  .first().json;

const taskMap = {};
taskResults.forEach(item => {
  const t = item.json;
  if (t.entity_id && t.id) {
    if (!taskMap[t.entity_id]) taskMap[t.entity_id] = {};
    taskMap[t.entity_id][t.task_type] = t.id;
  }
});

return [{
  json: {
    success: true,
    message: routeData.successCount + ' of '
      + routeData.totalCount
      + ' appointment(s) saved successfully',
    data: {
      appointments: routeData.allResults,
      backgroundTasks: taskMap
    },
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Async response with task IDs

// Format Simple Response - v1.0.0
// No background tasks needed

const data = $input.first().json;

return [{
  json: {
    success: true,
    message: data.successCount + ' of '
      + data.totalCount
      + ' appointment(s) saved successfully',
    data: {
      appointments: data.allResults,
      backgroundTasks: {}
    },
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Simple sync response

// Format Error Response - v1.0.0

const err = $input.first().json;

return [{
  json: {
    success: false,
    message: err.message || 'Failed to save appointment',
    error: err.error || 'Unknown error',
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Standard error response

// Unauthorized Response - v1.0.0

const err = $input.first().json;

return [{
  json: {
    success: false,
    error: {
      message: err.message || 'Unauthorized access',
      statusCode: err.statusCode || 401
    },
    timestamp: err.timestamp
      || new Date().toISOString()
  }
}];
// v1.0.0 - Unauthorized error response

// Prepare Traffic API Requests - v1.0.0
// Builds Maps API params for each appointment

const taskItems = $input.all();
const mapsKey = $('Get Maps API Key - Supabase')
  .first().json.value;

if (!mapsKey) {
  console.error('Google Maps API key not found');
  return taskItems.map(item => ({
    json: {
      taskId: item.json.id,
      branchError: 'true',
      errorMessage: 'Google Maps API key not found'
    }
  }));
}

return taskItems.map(item => {
  const t = item.json;
  const apt = $('Prepare Background Tasks - Code').all()
    .find(i =>
      String(i.json.entity_id) === String(t.entity_id)
    )?.json?.appointmentData;

  if (!apt) {
    return {
      json: {
        taskId: t.id,
        branchError: 'true',
        errorMessage: 'Appointment data not found'
      }
    };
  }

  const aptType = apt.appointment_type || 'round_trip';
  const dir = apt.trip_direction || 'to_clinic';

  let origins, destinations;
  if (aptType === 'one_way' && dir === 'to_home') {
    origins = apt.locationaddress;
    destinations = apt.pickup_address;
  } else {
    origins = apt.pickup_address;
    destinations = apt.locationaddress;
  }

  const apptDT = new Date(apt.appointmenttime);
  const depTime = Math.floor(apptDT.getTime() / 1000);

  return {
    json: {
      taskId: t.id,
      appointmentId: t.entity_id,
      branchError: 'false',
      origins: origins,
      destinations: destinations,
      apiKey: mapsKey,
      departureTime: depTime,
      appointmentType: aptType,
      tripDirection: dir,
      appointmentDateTime: apt.appointmenttime,
      appointmentLength: apt.this_appointment_length
        || parseInt(apt.appointmentLength) || 120
    }
  };
});
// v1.0.0 - Prepare traffic calc requests

// Calculate P75 Transit Time - v1.0.0
// Uses duration (no traffic) + duration_in_traffic

const items = $input.all();
const origReqs = $('Prepare Traffic Requests - Code')
  .all();

return items.map((item, i) => {
  const req = origReqs[i]?.json;
  if (!req || req.branchError === 'true') {
    return {
      json: {
        taskId: req?.taskId,
        appointmentId: req?.appointmentId,
        calcError: 'true',
        errorMessage: req?.errorMessage
          || 'Preparation failed'
      }
    };
  }

  const m = item.json;
  const el = m.rows?.[0]?.elements?.[0];

  if (!el || el.status !== 'OK') {
    return {
      json: {
        taskId: req.taskId,
        appointmentId: req.appointmentId,
        calcError: 'true',
        errorMessage: 'Maps API returned '
          + (el?.status || 'no data')
      }
    };
  }

  const noTraffic = el.duration.value;
  const pessimistic = el.duration_in_traffic
    ? el.duration_in_traffic.value : noTraffic;

  const p75sec = noTraffic
    + (pessimistic - noTraffic) * 0.75;
  const p75min = Math.ceil(p75sec / 60);
  const rounded = Math.ceil(p75min / 5) * 5;
  const newTransit = Math.max(rounded, 5);

  const apptDT = new Date(req.appointmentDateTime);
  const length = req.appointmentLength;
  const aptType = req.appointmentType;
  const dir = req.tripDirection;

  let pickupTime, dropOffTime;

  if (aptType === 'one_way') {
    if (dir === 'to_home') {
      pickupTime = apptDT.toISOString();
      const d = new Date(
        apptDT.getTime() + (newTransit * 60000)
      );
      dropOffTime = d.toISOString();
    } else {
      const p = new Date(
        apptDT.getTime() - (newTransit * 60000)
      );
      pickupTime = p.toISOString();
      dropOffTime = apptDT.toISOString();
    }
  } else {
    const p = new Date(
      apptDT.getTime() - (newTransit * 60000)
    );
    pickupTime = p.toISOString();
    const total = length + newTransit;
    const d = new Date(
      apptDT.getTime() + (total * 60000)
    );
    dropOffTime = d.toISOString();
  }

  const distKm = el.distance
    ? parseFloat(
        (el.distance.value / 1000).toFixed(2)
      )
    : null;

  return {
    json: {
      taskId: req.taskId,
      appointmentId: req.appointmentId,
      calcError: 'false',
      newTransitTime: newTransit,
      pickupTime: pickupTime,
      dropOffTime: dropOffTime,
      driverTotalDistance: distKm,
      durationNoTraffic: Math.round(noTraffic / 60),
      durationPessimistic: Math.round(
        pessimistic / 60
      ),
      p75Minutes: p75min
    }
  };
});
// v1.0.0 - P75 transit time calculation

// Mark Task Completed - v1.0.0

const d = $input.first().json;
const calcData = $('Calculate P75 Transit - Code')
  .all().find(i =>
    String(i.json.appointmentId)
      === String(d.id || d.appointmentId)
  )?.json;

return [{
  json: {
    taskId: calcData?.taskId || d.taskId,
    status: 'completed',
    completed_at: new Date().toISOString(),
    result: JSON.stringify({
      transit_minutes: calcData?.newTransitTime,
      distance_km: calcData?.driverTotalDistance,
      duration_no_traffic: calcData?.durationNoTraffic,
      duration_pessimistic:
        calcData?.durationPessimistic,
      p75_minutes: calcData?.p75Minutes
    }),
    error_message: null
  }
}];
// v1.0.0 - Mark task completed with result

// Mark Task Failed - v1.0.0

const d = $input.first().json;

return [{
  json: {
    taskId: d.taskId,
    status: 'failed',
    completed_at: new Date().toISOString(),
    result: null,
    error_message: d.errorMessage
      || 'Traffic calculation failed'
  }
}];
// v1.0.0 - Mark task failed with error
